package ra.edu.shoesphere.service.impl;
import lombok.RequiredArgsConstructor; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import ra.edu.shoesphere.model.dto.request.CartItemRequestDTO; import ra.edu.shoesphere.model.dto.response.CartItemResponseDTO; import ra.edu.shoesphere.model.entity.*; import ra.edu.shoesphere.repository.*; import ra.edu.shoesphere.service.CartService; import java.util.*;
@Service
@RequiredArgsConstructor
@Transactional public class CartServiceImpl implements CartService { private final UserRepository users; private final ShoeRepository shoes; private final CartItemRepository items; private User u(String e){return users.findByEmail(e).orElseThrow(()->new IllegalArgumentException("User not found."));} private CartItemResponseDTO m(CartItem i){Shoe s=i.getShoe();return CartItemResponseDTO.builder().id(i.getId()).shoeId(s.getId()).name(s.getName()).imageUrl(s.getImageUrl()).price(s.getPrice()).quantity(i.getQuantity()).stockQuantity(s.getStockQuantity()).build();} public List<CartItemResponseDTO> get(String e){return items.findByUserOrderByIdDesc(u(e)).stream().map(this::m).toList();} public CartItemResponseDTO add(String e,CartItemRequestDTO r){User u=u(e);Shoe s=shoes.findShoeDetailJPQL(r.getShoeId()).orElseThrow(()->new IllegalArgumentException("Shoe not found."));CartItem i=items.findByUserAndShoe(u,s).orElseGet(()->{CartItem x=new CartItem();x.setUser(u);x.setShoe(s);x.setQuantity(0);return x;});i.setQuantity(i.getQuantity()+r.getQuantity());return m(items.save(i));} public CartItemResponseDTO update(String e,Long id,Integer q){CartItem i=items.findByIdAndUser(id,u(e)).orElseThrow(()->new IllegalArgumentException("Cart item not found."));i.setQuantity(q);return m(items.save(i));} public void delete(String e,Long id){items.delete(items.findByIdAndUser(id,u(e)).orElseThrow(()->new IllegalArgumentException("Cart item not found.")));} }
